    const X2 = new Float32Array(size);
    const Y2 = new Float32Array(size);
    const XY = new Float32Array(size);

    for (let i = 0; i < size; i++) {
      const x = gray1[i];
      const y = gray2[i];
      X2[i] = x * x;
      Y2[i] = y * y;
      XY[i] = x * y;
    }

    const mu_x = gaussianBlur(gray1, w, h);
    const mu_y = gaussianBlur(gray2, w, h);
    const mu_x2 = gaussianBlur(X2, w, h);
    const mu_y2 = gaussianBlur(Y2, w, h);
