      const my = mu_y[i];
      const sig2_x = mu_x2[i] - mx * mx;
      const sig2_y = mu_y2[i] - my * my;
      const sig_xy = mu_xy[i] - mx * my;

      const s2_x = Math.max(0, sig2_x);
      const s2_y = Math.max(0, sig2_y);

      const num = (2 * mx * my + c1) * (2 * sig_xy + c2);
