      const mu_x = gaussianBlur(g1, currentW, currentH);
      const mu_y = gaussianBlur(g2, currentW, currentH);
      const mu_x2 = gaussianBlur(X2, currentW, currentH);
      const mu_y2 = gaussianBlur(Y2, currentW, currentH);
      const mu_xy = gaussianBlur(XY, currentW, currentH);

