    let yr = y / 100.000;
    let zr = z / 108.883;

    xr = xr > 0.008856 ? Math.pow(xr, 1/3) : (7.787 * xr) + (16 / 116);
    yr = yr > 0.008856 ? Math.pow(yr, 1/3) : (7.787 * yr) + (16 / 116);
    zr = zr > 0.008856 ? Math.pow(zr, 1/3) : (7.787 * zr) + (16 / 116);

    const L = (116 * yr) - 16;
    const l_a = 500 * (xr - yr);
    const l_b = 200 * (yr - zr);

